package com.enterprise.auth.service;

import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

import java.security.SecureRandom;
import java.util.ArrayList;
import java.util.List;

@Service
public class BackupCodeGeneratorService {

    private static final int CODE_LENGTH = 8;
    private static final int NUM_CODES = 10;
    private static final String ALLOWED_CHARS = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";
    private static final SecureRandom SECURE_RANDOM = new SecureRandom();

    private final PasswordEncoder passwordEncoder;

    public BackupCodeGeneratorService(PasswordEncoder passwordEncoder) {
        this.passwordEncoder = passwordEncoder;
    }

    public List<String> generatePlaintextCodes() {
        List<String> codes = new ArrayList<>(NUM_CODES);
        for (int i = 0; i < NUM_CODES; i++) {
            codes.add(generateSingleCode());
        }
        return codes;
    }

    public String hashCode(String plaintextCode) {
        return passwordEncoder.encode(normalizeCode(plaintextCode));
    }

    public boolean verifyCode(String plaintextCode, String hashedCode) {
        return passwordEncoder.matches(normalizeCode(plaintextCode), hashedCode);
    }

    private String generateSingleCode() {
        StringBuilder sb = new StringBuilder(CODE_LENGTH + 1);
        for (int i = 0; i < CODE_LENGTH; i++) {
            if (i == CODE_LENGTH / 2) {
                sb.append('-');
            }
            int index = SECURE_RANDOM.nextInt(ALLOWED_CHARS.length());
            sb.append(ALLOWED_CHARS.charAt(index));
        }
        return sb.toString();
    }

    private String normalizeCode(String code) {
        if (code == null) {
            return "";
        }
        return code.replaceAll("[^A-Za-z0-9]", "").toUpperCase();
    }
}

