package com.enterprise.auth.service;

import com.enterprise.auth.entity.AuditLog;
import com.enterprise.auth.repository.AuditLogRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

@Service
public class AuditService {

    private static final Logger logger = LoggerFactory.getLogger(AuditService.class);

    private final AuditLogRepository auditLogRepository;

    public AuditService(AuditLogRepository auditLogRepository) {
        this.auditLogRepository = auditLogRepository;
    }

    public void logEvent(Long userId, String eventType, String details, String ipAddress, boolean success) {
        // Never log sensitive data like codes, tokens, or secrets
        String sanitizedDetails = sanitizeForLog(details);
        AuditLog auditLog = new AuditLog(userId, eventType, sanitizedDetails, sanitizeIpAddress(ipAddress), success);
        auditLogRepository.save(auditLog);
        logger.info("Audit event: userId={}, type={}, success={}", userId, eventType, success);
    }

    private String sanitizeForLog(String input) {
        if (input == null) return null;
        // Remove any potential code or secret values, limit length
        String sanitized = input.replaceAll("[A-Z0-9]{4}-[A-Z0-9]{4}", "[REDACTED]");
        if (sanitized.length() > 512) {
            sanitized = sanitized.substring(0, 512);
        }
        return sanitized;
    }

    private String sanitizeIpAddress(String ip) {
        if (ip == null) return null;
        // Basic IP address validation
        if (ip.matches("^[0-9a-fA-F.:]{1,45}$")) {
            return ip;
        }
        return "INVALID";
    }
}

