package com.enterprise.auth.service;

import com.enterprise.auth.entity.User;
import com.enterprise.auth.repository.UserRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.Duration;
import java.time.Instant;

@Service
public class RateLimitService {

    private static final int MAX_FAILED_ATTEMPTS = 5;
    private static final Duration LOCKOUT_DURATION = Duration.ofMinutes(30);

    private final UserRepository userRepository;

    public RateLimitService(UserRepository userRepository) {
        this.userRepository = userRepository;
    }

    public boolean isLockedOut(User user) {
        if (user.getBackupCodeLockoutUntil() != null && Instant.now().isBefore(user.getBackupCodeLockoutUntil())) {
            return true;
        }
        // Reset if lockout has expired
        if (user.getBackupCodeLockoutUntil() != null && Instant.now().isAfter(user.getBackupCodeLockoutUntil())) {
            user.setFailedBackupCodeAttempts(0);
            user.setBackupCodeLockoutUntil(null);
            userRepository.save(user);
        }
        return false;
    }

    @Transactional
    public void recordFailedAttempt(User user) {
        int attempts = user.getFailedBackupCodeAttempts() + 1;
        user.setFailedBackupCodeAttempts(attempts);
        if (attempts >= MAX_FAILED_ATTEMPTS) {
            user.setBackupCodeLockoutUntil(Instant.now().plus(LOCKOUT_DURATION));
        }
        userRepository.save(user);
    }

    @Transactional
    public void resetFailedAttempts(User user) {
        user.setFailedBackupCodeAttempts(0);
        user.setBackupCodeLockoutUntil(null);
        userRepository.save(user);
    }
}

