package com.enterprise.auth.service;

import com.enterprise.auth.entity.BackupCode;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.exception.AccountLockedException;
import com.enterprise.auth.exception.BackupCodeException;
import com.enterprise.auth.exception.UserNotFoundException;
import com.enterprise.auth.repository.BackupCodeRepository;
import com.enterprise.auth.repository.UserRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.Duration;
import java.time.Instant;
import java.util.ArrayList;
import java.util.List;

@Service
public class BackupCodeService {

    private static final Logger logger = LoggerFactory.getLogger(BackupCodeService.class);
    private static final Duration CODE_VALIDITY_PERIOD = Duration.ofDays(365);

    private final BackupCodeRepository backupCodeRepository;
    private final UserRepository userRepository;
    private final BackupCodeGeneratorService codeGenerator;
    private final AuditService auditService;
    private final RateLimitService rateLimitService;

    public BackupCodeService(BackupCodeRepository backupCodeRepository,
                             UserRepository userRepository,
                             BackupCodeGeneratorService codeGenerator,
                             AuditService auditService,
                             RateLimitService rateLimitService) {
        this.backupCodeRepository = backupCodeRepository;
        this.userRepository = userRepository;
        this.codeGenerator = codeGenerator;
        this.auditService = auditService;
        this.rateLimitService = rateLimitService;
    }

    @Transactional
    public List<String> generateBackupCodes(Long userId, String ipAddress) {
        User user = userRepository.findById(userId)
                .orElseThrow(() -> new UserNotFoundException("User not found"));

        if (!user.isMfaEnabled()) {
            throw new BackupCodeException("MFA must be enabled before generating backup codes");
        }

        // Invalidate all existing backup codes for this user
        backupCodeRepository.deleteAllByUserId(userId);

        List<String> plaintextCodes = codeGenerator.generatePlaintextCodes();
        Instant now = Instant.now();
        Instant expiresAt = now.plus(CODE_VALIDITY_PERIOD);

        List<BackupCode> backupCodes = new ArrayList<>();
        for (String plaintext : plaintextCodes) {
            String hashed = codeGenerator.hashCode(plaintext);
            BackupCode backupCode = new BackupCode(userId, hashed, now, expiresAt);
            backupCodes.add(backupCode);
        }

        backupCodeRepository.saveAll(backupCodes);

        auditService.logEvent(userId, "BACKUP_CODES_GENERATED",
                "New backup codes generated, previous codes invalidated", ipAddress, true);

        logger.info("Generated backup codes for userId={}", userId);

        // Return plaintext codes ONLY this one time - they must be shown to the user
        // and never stored in plaintext
        return plaintextCodes;
    }

    @Transactional
    public boolean verifyBackupCode(Long userId, String submittedCode, String ipAddress) {
        if (submittedCode == null || submittedCode.isBlank()) {
            throw new BackupCodeException("Backup code must not be empty");
        }

        // Input validation: backup codes follow a specific format
        String normalized = submittedCode.replaceAll("[^A-Za-z0-9]", "").toUpperCase();
        if (normalized.length() != 8) {
            throw new BackupCodeException("Invalid backup code format");
        }

        User user = userRepository.findById(userId)
                .orElseThrow(() -> new UserNotFoundException("User not found"));

        if (!user.isMfaEnabled()) {
            throw new BackupCodeException("MFA is not enabled for this account");
        }

        // Check rate limiting / lockout
        if (rateLimitService.isLockedOut(user)) {
            auditService.logEvent(userId, "BACKUP_CODE_ATTEMPT_LOCKED_OUT",
                    "Backup code attempt while account is locked out", ipAddress, false);
            throw new AccountLockedException("Account is temporarily locked due to too many failed attempts. Please try again later.");
        }

        List<BackupCode> unusedCodes = backupCodeRepository.findByUserIdAndUsedFalse(userId);

        for (BackupCode backupCode : unusedCodes) {
            // Check expiration
            if (Instant.now().isAfter(backupCode.getExpiresAt())) {
                continue;
            }

            if (codeGenerator.verifyCode(submittedCode, backupCode.getCodeHash())) {
                // Mark code as used - single use only
                backupCode.setUsed(true);
                backupCode.setUsedAt(Instant.now());
                backupCodeRepository.save(backupCode);

                // Reset failed attempts on success
                rateLimitService.resetFailedAttempts(user);

                long remainingCodes = backupCodeRepository.countByUserIdAndUsedFalse(userId);

                auditService.logEvent(userId, "BACKUP_CODE_USED",
                        "Backup code successfully used. Remaining codes: " + remainingCodes, ipAddress, true);

                logger.info("Backup code verified for userId={}, remaining={}", userId, remainingCodes);

                return true;
            }
        }

        // Failed attempt
        rateLimitService.recordFailedAttempt(user);

        auditService.logEvent(userId, "BACKUP_CODE_FAILED",
                "Invalid backup code attempt", ipAddress, false);

        logger.warn("Failed backup code attempt for userId={}", userId);

        return false;
    }

    public long getRemainingCodesCount(Long userId) {
        userRepository.findById(userId)
                .orElseThrow(() -> new UserNotFoundException("User not found"));
        return backupCodeRepository.countByUserIdAndUsedFalse(userId);
    }

    @Transactional
    public void revokeAllBackupCodes(Long userId, String ipAddress) {
        userRepository.findById(userId)
                .orElseThrow(() -> new UserNotFoundException("User not found"));

        backupCodeRepository.deleteAllByUserId(userId);

        auditService.logEvent(userId, "BACKUP_CODES_REVOKED",
                "All backup codes revoked", ipAddress, true);

        logger.info("All backup codes revoked for userId={}", userId);
    }
}

