package com.enterprise.auth.service;

import com.enterprise.auth.entity.User;
import com.enterprise.auth.exception.UserNotFoundException;
import com.enterprise.auth.repository.UserRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;

@Service
public class MfaService {

    private final UserRepository userRepository;
    private final BackupCodeService backupCodeService;
    private final AuditService auditService;

    public MfaService(UserRepository userRepository,
                      BackupCodeService backupCodeService,
                      AuditService auditService) {
        this.userRepository = userRepository;
        this.backupCodeService = backupCodeService;
        this.auditService = auditService;
    }

    @Transactional
    public List<String> enableMfa(Long userId, String ipAddress) {
        User user = userRepository.findById(userId)
                .orElseThrow(() -> new UserNotFoundException("User not found"));

        user.setMfaEnabled(true);
        // In production, you would also set up TOTP secret here (encrypted)
        userRepository.save(user);

        auditService.logEvent(userId, "MFA_ENABLED", "MFA enabled for user", ipAddress, true);

        // Generate backup codes when MFA is enabled
        return backupCodeService.generateBackupCodes(userId, ipAddress);
    }

    @Transactional
    public void disableMfa(Long userId, String ipAddress) {
        User user = userRepository.findById(userId)
                .orElseThrow(() -> new UserNotFoundException("User not found"));

        user.setMfaEnabled(false);
        user.setMfaSecretEncrypted(null);
        userRepository.save(user);

        // Revoke all backup codes when MFA is disabled
        backupCodeService.revokeAllBackupCodes(userId, ipAddress);

        auditService.logEvent(userId, "MFA_DISABLED", "MFA disabled for user", ipAddress, true);
    }
}

