package com.enterprise.auth.controller;

import com.enterprise.auth.dto.*;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.exception.UserNotFoundException;
import com.enterprise.auth.repository.UserRepository;
import com.enterprise.auth.service.BackupCodeService;
import com.enterprise.auth.service.MfaService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.validation.Valid;
import org.springframework.http.HttpHeaders;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.bind.annotation.*;

import java.util.List;

@RestController
@RequestMapping("/api/v1/mfa")
public class BackupCodeController {

    private final BackupCodeService backupCodeService;
    private final MfaService mfaService;
    private final UserRepository userRepository;

    public BackupCodeController(BackupCodeService backupCodeService,
                                MfaService mfaService,
                                UserRepository userRepository) {
        this.backupCodeService = backupCodeService;
        this.mfaService = mfaService;
        this.userRepository = userRepository;
    }

    @PostMapping("/enable")
    public ResponseEntity<BackupCodesResponse> enableMfa(HttpServletRequest request) {
        Long userId = getAuthenticatedUserId();
        String ipAddress = getClientIpAddress(request);

        List<String> codes = mfaService.enableMfa(userId, ipAddress);

        // Set cache control headers to prevent caching of sensitive response
        return ResponseEntity.ok()
                .header(HttpHeaders.CACHE_CONTROL, "no-store, no-cache, must-revalidate")
                .header(HttpHeaders.PRAGMA, "no-cache")
                .body(new BackupCodesResponse(codes,
                        "Store these backup codes securely. They will not be shown again. " +
                        "Each code can only be used once."));
    }

    @PostMapping("/disable")
    public ResponseEntity<Void> disableMfa(HttpServletRequest request) {
        Long userId = getAuthenticatedUserId();
        String ipAddress = getClientIpAddress(request);

        mfaService.disableMfa(userId, ipAddress);

        return ResponseEntity.noContent().build();
    }

    @PostMapping("/backup-codes/regenerate")
    public ResponseEntity<BackupCodesResponse> regenerateBackupCodes(HttpServletRequest request) {
        Long userId = getAuthenticatedUserId();
        String ipAddress = getClientIpAddress(request);

        List<String> codes = backupCodeService.generateBackupCodes(userId, ipAddress);

        return ResponseEntity.ok()
                .header(HttpHeaders.CACHE_CONTROL, "no-store, no-cache, must-revalidate")
                .header(HttpHeaders.PRAGMA, "no-cache")
                .body(new BackupCodesResponse(codes,
                        "New backup codes generated. Previous codes have been invalidated. " +
                        "Store these codes securely."));
    }

    @PostMapping("/backup-codes/verify")
    public ResponseEntity<VerificationResponse> verifyBackupCode(
            @Valid @RequestBody BackupCodeVerificationRequest verificationRequest,
            HttpServletRequest request) {
        Long userId = getAuthenticatedUserId();
        String ipAddress = getClientIpAddress(request);

        boolean verified = backupCodeService.verifyBackupCode(
                userId, verificationRequest.getBackupCode(), ipAddress);

        if (verified) {
            long remaining = backupCodeService.getRemainingCodesCount(userId);
            String message = "Backup code verified successfully.";
            if (remaining <= 3) {
                message += " Warning: You have only " + remaining + " backup codes remaining. " +
                          "Consider generating new codes.";
            }
            return ResponseEntity.ok(new VerificationResponse(true, message, remaining));
        } else {
            return ResponseEntity.ok(new VerificationResponse(false,
                    "Invalid backup code. Please try again.", -1));
        }
    }

    @GetMapping("/backup-codes/status")
    public ResponseEntity<BackupCodeStatusResponse> getBackupCodeStatus() {
        Long userId = getAuthenticatedUserId();
        User user = userRepository.findById(userId)
                .orElseThrow(() -> new UserNotFoundException("User not found"));

        long remaining = backupCodeService.getRemainingCodesCount(userId);

        return ResponseEntity.ok(new BackupCodeStatusResponse(remaining, user.isMfaEnabled()));
    }

    @DeleteMapping("/backup-codes")
    public ResponseEntity<Void> revokeBackupCodes(HttpServletRequest request) {
        Long userId = getAuthenticatedUserId();
        String ipAddress = getClientIpAddress(request);

        backupCodeService.revokeAllBackupCodes(userId, ipAddress);

        return ResponseEntity.noContent().build();
    }

    private Long getAuthenticatedUserId() {
        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();
        if (authentication == null || !authentication.isAuthenticated()) {
            throw new SecurityException("User is not authenticated");
        }
        String username = authentication.getName();
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new UserNotFoundException("Authenticated user not found"));
        return user.getId();
    }

    private String getClientIpAddress(HttpServletRequest request) {
        // In production behind a reverse proxy, use X-Forwarded-For with proper validation
        // Only trust X-Forwarded-For if the request comes from a known proxy
        String ip = request.getRemoteAddr();
        if (ip != null && ip.matches("^[0-9a-fA-F.:]{1,45}$")) {
            return ip;
        }
        return "UNKNOWN";
    }
}

// ============================================================
// GlobalExceptionHandler.java
// ============================================================
package com.enterprise.auth.controller;

import com.enterprise.auth.exception.AccountLockedException;
import com.enterprise.auth.exception.BackupCodeException;
import com.enterprise.auth.exception.UserNotFoundException;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.MethodArgumentNotValidException;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;

import java.util.HashMap;
import java.util.Map;

@RestControllerAdvice
public class GlobalExceptionHandler {

    private static final Logger logger = LoggerFactory.getLogger(GlobalExceptionHandler.class);

    @ExceptionHandler(BackupCodeException.class)
    public ResponseEntity<Map<String, String>> handleBackupCodeException(BackupCodeException ex) {
        Map<String, String> error = new HashMap<>();
        error.put("error", ex.getMessage());
        return ResponseEntity.badRequest().body(error);
    }

    @ExceptionHandler(UserNotFoundException.class)
    public ResponseEntity<Map<String, String>> handleUserNotFoundException(UserNotFoundException ex) {
        Map<String, String> error = new HashMap<>();
        error.put("error", "User not found");
        return ResponseEntity.status(HttpStatus.NOT_FOUND).body(error);
    }

    @ExceptionHandler(AccountLockedException.class)
    public ResponseEntity<Map<String, String>> handleAccountLockedException(AccountLockedException ex) {
        Map<String, String> error = new HashMap<>();
        error.put("error", ex.getMessage());
        return ResponseEntity.status(HttpStatus.TOO_MANY_REQUESTS).body(error);
    }

    @ExceptionHandler(SecurityException.class)
    public ResponseEntity<Map<String, String>> handleSecurityException(SecurityException ex) {
        Map<String, String> error = new HashMap<>();
        error.put("error", "Authentication required");
        return ResponseEntity.status(HttpStatus.UNAUTHORIZED).body(error);
    }

    @ExceptionHandler(MethodArgumentNotValidException.class)
    public ResponseEntity<Map<String, String>> handleValidationException(MethodArgumentNotValidException ex) {
        Map<String, String> error = new HashMap<>();
        error.put("error", "Invalid input");
        ex.getBindingResult().getFieldErrors().forEach(fieldError ->
                error.put(fieldError.getField(), fieldError.getDefaultMessage()));
        return ResponseEntity.badRequest().body(error);
    }

    @ExceptionHandler(Exception.class)
    public ResponseEntity<Map<String, String>> handleGenericException(Exception ex) {
        logger.error("Unexpected error occurred", ex);
        Map<String, String> error = new HashMap<>();
        // Do not expose internal error details to the client
        error.put("error", "An internal error occurred. Please try again later.");
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(error);
    }
}

